// Generic identity function — preserves the exact type
function firstElement<T>(arr: T[]): T | undefined {
  return arr[0];
}

let num = firstElement([1, 2, 3]);
// TypeScript infers: number
console.log(num);
// Expected output: 1

let str = firstElement(['a', 'b', 'c']);
// TypeScript infers: string
console.log(str);
// Expected output: a

// Constrained generic — T must have a name property
function greet<T extends { name: string }>(obj: T): string {
  return 'Hello, ' + obj.name;
}

console.log(greet({ name: 'Alice', age: 30 }));
// Expected output: Hello, Alice
